var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"침식체가 계속 몰려와! 정말 이대로 괜찮은 거 맞아?","JPN":"侵食体がとめどなく押し寄せてくるわ！　本当にこのままで大丈夫なの？","ENG":"C.O.s won't stop coming! Can we really survive this?","TWN":"侵蝕體正不斷地湧來！這樣下去真的沒問題嗎？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"한눈 팔지 말고 집중하세요!","JPN":"わき目をふらずに集中を！　","ENG":"Stop talking and focus!","TWN":"不要東張西望，集中注意力！"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"전선을 사수하고 있으면 사령관님께서 해결책을 마련하실 겁니다!","JPN":"我々が戦線を死守する間、司令官が対策を講じるはずです！","ENG":"If we just keep fighting, the Commander will come up with a solution.","TWN":"只要死守住前線，司令官大人一定有辦法解決的！"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......상황이 좋지 않군.","JPN":"……まずい状況になったな。","ENG":"The situation is not in our favor.","TWN":"……情況不太好呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이크!","JPN":"ジェイク！","ENG":"Jake!","TWN":"傑克！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"네? 네! 사령관님!","JPN":"はい？　はい！　司令官！","ENG":"Huh? Yes, Commander!","TWN":"什麼？是的！司令官！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"지금부터 이곳의 지휘는 자네에게 맡긴다.","JPN":"これよりここの指揮は君に任せる。","ENG":"I'm leaving you in charge of this place.","TWN":"現在開始，這裡就交給你指揮了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아와 카일을 이끌고 등대를 방어하도록.","JPN":"シルビアやカイルとともに灯台を守るように。","ENG":"Protect the Lighthouse with Sylvia and Kyle.","TWN":"你帶著希爾維亞和凱爾，去燈塔那裡進行防衛。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"네? 그럼 사령관님은......?","JPN":"はい？　では、司令官は……？","ENG":"Huh? But what about you, Commander?","TWN":"咦？那司令官呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나는 뉴 오하이오로 차원 폭풍 내부에 돌입하여 도미닉과 선발대를 구원하러 가겠다.","JPN":"私はニューオハイオで次元の暴風の中に入り、ドミニークと選抜隊を助けにいく。","ENG":"I'm going to drive the New Ohio into the dimensional storm and save Dominic and his advance party.","TWN":"我要坐新俄亥俄衝進次元風暴內部，去救出多明尼克和先頭部隊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"사령관님 혼자서 말입니까? 하지만 그건 너무 위험합니다.","JPN":"司令官一人でですか？　それは危険過ぎます。","ENG":"By yourself, Commander? That's too dangerous.","TWN":"司令官一個人去？可是那樣太危險了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"걱정 말게. 위험한 작전이 바로 내 특기니까.","JPN":"案ずるな。危険な作戦こそが私の専門だからな。","ENG":"Don't worry. Dangerous operations are my forte.","TWN":"不用擔心，畢竟進行危險的作戰正是我的特長。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 뉴 오하이오는 이런 불안정한 차원간 항해에 저항성을 가지도록 설계된 전략 함선이야.","JPN":"それに、ニューオハイオはこのように不安定な次元間の航海に耐えられるよう設計された戦略艦船だ。","ENG":"Besides, the New Ohio is a tactical ship designed to endure even the most unstable interdimensional trip.","TWN":"而且作為一艘戰略艦船，新俄亥俄正是被設計成能夠抵抗這種不穩定的次元間航行。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"등대만 무사하다면 차원 폭풍 속이라고 해도 충분히 순항이 가능해.","JPN":"灯台さえ無事なら、次元の暴風の中でも十分巡航できる。","ENG":"So long as the Lighthouse is safe, she can sail smoothly, even inside the dimensional storm.","TWN":"只要燈塔沒事，就算在次元風暴內部也能夠順利航行。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 그렇다고 해도...... 제가 지휘를 맡을 수 있을지......","JPN":"ですが、そうは言っても……俺に指揮役がつとまるかどうか……","ENG":"But still... I don't know if I can command the others...","TWN":"就算如此……我有辦法擔負指揮的重任嗎……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"차원 폭풍 속에서 연락이 두절되었다면 부사령관님이 무사할 가능성은 거의 없습니다.","JPN":"次元の暴風の中で音信不通になったなら、\\n副司令官が無事な可能性はほぼゼロです。","ENG":"The Deputy Commander is lost in the middle of that dimensional storm, and there's almost zero possibility of him returning safely.","TWN":"在次元風暴內部失去聯絡的話，副司令官幾乎不可能平安無事。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"차라리 살아남은 사람만이라도 모아 후퇴하시는 게......","JPN":"こうなった以上、生存メンバーだけでも集めて退却したほうが……","ENG":"Perhaps we should just leave with the others who are still here.","TWN":"我們還不如集合起倖存者撤退……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};